import { useParams } from "react-router-dom";
import { useState } from "react";

export default function IncidentDetail() {
  const { id } = useParams();   // ✅ FIX 1: define id here

  const [form, setForm] = useState({
    start: "",
    end: "",
    rootCause: "",
    fix: "",
    prevention: ""
  });  // ✅ FIX 2: define form state

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const res = await fetch(`http://localhost:8000/close/${id}`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(form)
      });

      if (!res.ok) throw new Error("Server error");

      const data = await res.json();
      console.log(data);

      alert("Incident Closed!");
    } catch (err) {
      console.error(err);
      alert("Error connecting to backend");
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Incident {id}</h2>

      <form onSubmit={handleSubmit}>
        <input type="datetime-local" name="start" onChange={handleChange} /><br />
        <input type="datetime-local" name="end" onChange={handleChange} /><br />
        <input name="rootCause" placeholder="Root Cause" onChange={handleChange} /><br />
        <input name="fix" placeholder="Fix" onChange={handleChange} /><br />
        <input name="prevention" placeholder="Prevention" onChange={handleChange} /><br />

        <button type="submit">Close Incident</button>
      </form>
    </div>
  );
}
